# Vitest — Vite-Native Test Framework

Vitest is the test framework built on top of Vite. It uses Vite's transform pipeline, giving you native ESM, TypeScript, and JSX support without any extra configuration. The API mirrors Jest, so switching is low-friction.

## Quick Start

```bash
# Install vitest
npm install -D vitest

# Run tests (watch mode by default in dev)
npx vitest

# Run once and exit (CI mode)
npx vitest run

# Run with coverage
npx vitest run --coverage

# Run with browser UI dashboard
npx vitest --ui

# Run benchmarks
npx vitest bench
```

Create your first test:

```typescript
// src/math.ts
export function sum(a: number, b: number): number {
  return a + b;
}

// src/math.test.ts
import { describe, it, expect } from 'vitest';
import { sum } from './math';

describe('sum', () => {
  it('adds two numbers', () => {
    expect(sum(1, 2)).toBe(3);
  });

  it('handles negative numbers', () => {
    expect(sum(-1, 1)).toBe(0);
  });
});
```

## Configuration

Vitest reads config from `vitest.config.ts` (preferred) or the `test` block in `vite.config.ts`.

### Standalone vitest.config.ts

```typescript
import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    // Test file patterns
    include: ['src/**/*.{test,spec}.{ts,tsx,js,jsx}'],
    exclude: ['node_modules', 'dist', 'e2e'],

    // Environment: 'node' (default), 'jsdom', 'happy-dom'
    environment: 'node',

    // Global test APIs (no imports needed)
    globals: true,

    // Setup files run before each test file
    setupFiles: ['./src/test/setup.ts'],

    // Coverage configuration
    coverage: {
      provider: 'v8',
      reporter: ['text', 'html', 'lcov'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.test.ts', 'src/**/*.d.ts'],
      thresholds: {
        lines: 80,
        branches: 80,
        functions: 80,
        statements: 80,
      },
    },

    // Timeouts
    testTimeout: 10000,
    hookTimeout: 10000,

    // Reporter
    reporters: ['default'],

    // Pool: 'threads' (default), 'forks', 'vmThreads'
    pool: 'threads',

    // Retry flaky tests
    retry: 0,

    // Type checking tests
    typecheck: {
      enabled: false,
      tsconfig: './tsconfig.json',
    },
  },
});
```

### Inside vite.config.ts

```typescript
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    environment: 'jsdom',
    globals: true,
    setupFiles: './src/test/setup.ts',
  },
});
```

### Environment Options

| Environment | Package | Use Case |
|-------------|---------|----------|
| `node` | built-in | Server-side code, utilities, APIs |
| `jsdom` | `jsdom` | DOM testing, React/Vue components |
| `happy-dom` | `happy-dom` | Faster DOM testing (less complete than jsdom) |
| `edge-runtime` | `@edge-runtime/vm` | Edge/Cloudflare Workers |

Per-file environment override with a magic comment:

```typescript
// @vitest-environment jsdom
import { describe, it, expect } from 'vitest';

describe('DOM test', () => {
  it('creates an element', () => {
    const el = document.createElement('div');
    expect(el).toBeDefined();
  });
});
```

## Writing Tests

Vitest uses the same API as Jest: `describe`, `it`/`test`, `expect`, `beforeEach`, `afterEach`, `beforeAll`, `afterAll`.

```typescript
import { describe, it, expect, beforeEach, afterEach } from 'vitest';

describe('UserService', () => {
  let service: UserService;

  beforeEach(() => {
    service = new UserService();
  });

  afterEach(() => {
    service.dispose();
  });

  it('creates a user', () => {
    const user = service.create({ name: 'Alice' });
    expect(user).toMatchObject({ name: 'Alice' });
    expect(user.id).toBeDefined();
  });

  it('throws on duplicate email', () => {
    service.create({ name: 'Alice', email: 'a@b.com' });
    expect(() => {
      service.create({ name: 'Bob', email: 'a@b.com' });
    }).toThrow('Email already exists');
  });

  it.each([
    { input: 'alice', expected: 'ALICE' },
    { input: 'bob', expected: 'BOB' },
  ])('uppercases $input to $expected', ({ input, expected }) => {
    expect(input.toUpperCase()).toBe(expected);
  });

  it.todo('should handle concurrent creates');

  it.skip('slow test', () => {
    // skipped
  });
});
```

### Async Tests

```typescript
import { it, expect } from 'vitest';

it('fetches data', async () => {
  const data = await fetchUsers();
  expect(data).toHaveLength(3);
});

it('rejects on error', async () => {
  await expect(fetchBadEndpoint()).rejects.toThrow('Not Found');
});
```

### Snapshot Testing

```typescript
import { it, expect } from 'vitest';

it('matches snapshot', () => {
  const result = generateConfig({ mode: 'production' });
  expect(result).toMatchSnapshot();
});

it('matches inline snapshot', () => {
  const result = formatUser({ name: 'Alice', age: 30 });
  expect(result).toMatchInlineSnapshot(`"Alice (30)"`);
});
```

Update snapshots: `npx vitest run --update` or press `u` in watch mode.

## Mocking with vi

Vitest provides the `vi` utility for mocking, spying, and stubbing.

### vi.fn() — Mock Functions

```typescript
import { it, expect, vi } from 'vitest';

it('tracks calls', () => {
  const fn = vi.fn();
  fn('hello');
  fn('world');

  expect(fn).toHaveBeenCalledTimes(2);
  expect(fn).toHaveBeenCalledWith('hello');
  expect(fn).toHaveBeenLastCalledWith('world');
});

it('returns mock values', () => {
  const fn = vi.fn()
    .mockReturnValueOnce(1)
    .mockReturnValueOnce(2)
    .mockReturnValue(99);

  expect(fn()).toBe(1);
  expect(fn()).toBe(2);
  expect(fn()).toBe(99);
});

it('mocks async functions', async () => {
  const fn = vi.fn().mockResolvedValue({ id: 1 });
  const result = await fn();
  expect(result).toEqual({ id: 1 });
});
```

### vi.mock() — Module Mocking

```typescript
import { describe, it, expect, vi } from 'vitest';
import { getUser } from './api';
import { fetchFromDB } from './db';

// Mock the entire module
vi.mock('./db', () => ({
  fetchFromDB: vi.fn().mockResolvedValue({ id: 1, name: 'Alice' }),
}));

describe('getUser', () => {
  it('returns user from DB', async () => {
    const user = await getUser(1);
    expect(user.name).toBe('Alice');
    expect(fetchFromDB).toHaveBeenCalledWith(1);
  });
});
```

vi.mock is hoisted to the top of the file automatically.

### vi.spyOn() — Spy on Methods

```typescript
import { it, expect, vi } from 'vitest';

it('spies on method', () => {
  const obj = { greet: (name: string) => `Hello ${name}` };
  const spy = vi.spyOn(obj, 'greet');

  obj.greet('Alice');

  expect(spy).toHaveBeenCalledWith('Alice');
  expect(spy).toHaveReturnedWith('Hello Alice');

  spy.mockRestore();
});
```

### vi.stubGlobal() — Stub Globals

```typescript
import { it, expect, vi, afterEach } from 'vitest';

afterEach(() => {
  vi.unstubAllGlobals();
});

it('stubs fetch', async () => {
  vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve({ data: 'test' }),
  }));

  const resp = await fetch('/api');
  const data = await resp.json();
  expect(data).toEqual({ data: 'test' });
});
```

### Timers

```typescript
import { it, expect, vi, beforeEach, afterEach } from 'vitest';

beforeEach(() => {
  vi.useFakeTimers();
});

afterEach(() => {
  vi.useRealTimers();
});

it('advances timers', () => {
  const fn = vi.fn();
  setTimeout(fn, 1000);

  vi.advanceTimersByTime(1000);
  expect(fn).toHaveBeenCalledOnce();
});
```

## Coverage

Vitest supports coverage via `@vitest/coverage-v8` (default, fast, V8-based) or `@vitest/coverage-istanbul` (traditional instrumentation).

```bash
# Install V8 coverage provider
npm install -D @vitest/coverage-v8

# Or Istanbul
npm install -D @vitest/coverage-istanbul

# Run with coverage
npx vitest run --coverage
```

Configure in vitest.config.ts:

```typescript
export default defineConfig({
  test: {
    coverage: {
      provider: 'v8',
      reporter: ['text', 'html', 'lcov', 'json'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.test.ts', 'src/**/*.d.ts', 'src/test/**'],
      thresholds: {
        lines: 80,
        branches: 75,
        functions: 80,
        statements: 80,
      },
    },
  },
});
```

## Watch Mode and UI

Vitest runs in watch mode by default during development. It re-runs only affected tests using Vite's module graph.

```bash
# Watch mode (default)
npx vitest

# Watch with UI dashboard
npx vitest --ui

# Watch specific files
npx vitest src/utils

# Keyboard shortcuts in watch mode:
#   a — re-run all tests
#   f — re-run only failed tests
#   u — update snapshots
#   p — filter by filename
#   t — filter by test name
#   q — quit
```

Install the UI package for the browser dashboard:

```bash
npm install -D @vitest/ui
npx vitest --ui
# Opens http://localhost:51204/__vitest__/
```

## Workspace / Monorepo Setup

Vitest workspaces let you run tests across multiple projects with different configs.

```typescript
// vitest.workspace.ts
import { defineWorkspace } from 'vitest/config';

export default defineWorkspace([
  // Glob pattern for project configs
  'packages/*/vitest.config.ts',

  // Or inline project definitions
  {
    test: {
      name: 'unit',
      include: ['src/**/*.test.ts'],
      environment: 'node',
    },
  },
  {
    test: {
      name: 'browser',
      include: ['src/**/*.browser.test.ts'],
      environment: 'jsdom',
    },
  },
]);
```

Run a specific project: `npx vitest --project unit`.

## Browser Mode

Test in real browsers instead of simulated DOM environments.

```bash
npm install -D @vitest/browser playwright
```

```typescript
// vitest.config.ts
import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    browser: {
      enabled: true,
      provider: 'playwright',
      instances: [
        { browser: 'chromium' },
      ],
    },
  },
});
```

## Migration from Jest

Vitest is API-compatible with Jest. Migration steps:

1. Install: `npm install -D vitest` and remove `jest`, `ts-jest`, `babel-jest`
2. Replace `jest.config.js` with `vitest.config.ts`
3. Replace `jest.fn()` with `vi.fn()`, `jest.mock()` with `vi.mock()`, etc.
4. Replace `jest.spyOn()` with `vi.spyOn()`
5. Change imports: `import { describe, it, expect, vi } from 'vitest'`
6. If using `globals: true`, no import changes are needed for describe/it/expect
7. Update `package.json` scripts: replace `jest` with `vitest run`

Search-and-replace mappings:

| Jest | Vitest |
|------|--------|
| `jest.fn()` | `vi.fn()` |
| `jest.mock()` | `vi.mock()` |
| `jest.spyOn()` | `vi.spyOn()` |
| `jest.useFakeTimers()` | `vi.useFakeTimers()` |
| `jest.advanceTimersByTime()` | `vi.advanceTimersByTime()` |
| `jest.clearAllMocks()` | `vi.clearAllMocks()` |
| `jest.resetAllMocks()` | `vi.resetAllMocks()` |
| `jest.restoreAllMocks()` | `vi.restoreAllMocks()` |

## Type Testing

Vitest can assert on TypeScript types at compile time.

```typescript
import { describe, it, expectTypeOf } from 'vitest';

describe('type tests', () => {
  it('checks return type', () => {
    expectTypeOf(sum).toBeFunction();
    expectTypeOf(sum).parameter(0).toBeNumber();
    expectTypeOf(sum).returns.toBeNumber();
  });

  it('checks object shape', () => {
    expectTypeOf<{ name: string; age: number }>().toMatchTypeOf<{ name: string }>();
  });
});
```

Enable in config:

```typescript
export default defineConfig({
  test: {
    typecheck: {
      enabled: true,
      tsconfig: './tsconfig.json',
    },
  },
});
```

Run: `npx vitest typecheck`.

## In-Source Testing

Write tests directly in source files. Vitest strips them from production builds.

```typescript
// src/math.ts
export function sum(a: number, b: number) {
  return a + b;
}

if (import.meta.vitest) {
  const { it, expect } = import.meta.vitest;
  it('sum', () => {
    expect(sum(1, 2)).toBe(3);
  });
}
```

Enable in config: `test: { includeSource: ['src/**/*.ts'] }` and add `/// <reference types="vitest" />` to a global `.d.ts` file.

## package.json Scripts

```json
{
  "scripts": {
    "test": "vitest",
    "test:run": "vitest run",
    "test:coverage": "vitest run --coverage",
    "test:ui": "vitest --ui",
    "test:watch": "vitest --watch",
    "test:bench": "vitest bench",
    "test:typecheck": "vitest typecheck"
  }
}
```

## Environment Variables

| Variable | Purpose |
|----------|----------|
| `VITEST` | Set to `true` when running inside Vitest |
| `VITEST_MODE` | Current mode: `run`, `watch`, `benchmark` |
| `VITEST_POOL_ID` | ID of the pool thread/fork (0-indexed) |
| `VITEST_WORKER_ID` | Unique worker ID across all pools |
| `TEST` | Set to `true` by Vitest |
| `NODE_ENV` | Set to `test` by default |

Access in tests or setup files:

```typescript
if (process.env.VITEST) {
  // Running inside Vitest
}
```

## CLI Reference

```bash
npx vitest                        # watch mode (default)
npx vitest run                    # run once and exit
npx vitest run src/utils          # run tests matching pattern
npx vitest run --reporter=json    # JSON output
npx vitest run --coverage         # with coverage
npx vitest --ui                   # browser UI dashboard
npx vitest --ui --coverage        # UI with coverage overlay
npx vitest bench                  # run benchmarks
npx vitest typecheck              # type-check test files
npx vitest --project unit         # run specific workspace project
npx vitest run --changed HEAD~1   # only tests affected by recent changes
npx vitest run --bail 3           # stop after 3 failures
npx vitest run --update           # update snapshots
npx vitest list                   # list all test files without running
```
